def has_samecoef(self, other):
    """Check if coefficients match.

    Parameters
    ----------
    other : class instance
        The other class must have the ``coef`` attribute.

    Returns
    -------
    bool : boolean
        True if the coefficients are the same, False otherwise.

    """
    return (
        len(self.coef) == len(other.coef)
        and np.all(self.coef == other.coef)
    )

def has_samedomain(self, other):
    """Check if domains match.

    Parameters
    ----------
    other : class instance
        The other class must have the ``domain`` attribute.

    Returns
    -------
    bool : boolean
        True if the domains are the same, False otherwise.

    """
    return np.all(self.domain == other.domain)

def has_samewindow(self, other):
    """Check if windows match.

    Parameters
    ----------
    other : class instance
        The other class must have the ``window`` attribute.

    Returns
    -------
    bool : boolean
        True if the windows are the same, False otherwise.

    """
    return np.all(self.window == other.window)

def has_sametype(self, other):
    """Check if types match.

    Parameters
    ----------
    other : object
        Class instance.

    Returns
    -------
    bool : boolean
        True if other is same class as self

    """
    return isinstance(other, self.__class__)

def _get_coefficients(self, other):
    """Interpret other as polynomial coefficients.

    The `other` argument is checked to see if it is of the same
    class as self with identical domain and window. If so,
    return its coefficients, otherwise return `other`.

    Parameters
    ----------
    other : anything
        Object to be checked.

    Returns
    -------
    coef
        The coefficients of`other` if it is a compatible instance,
        of ABCPolyBase, otherwise `other`.

    Raises
    ------
    TypeError
        When `other` is an incompatible instance of ABCPolyBase.

    """
    if isinstance(other, ABCPolyBase):
        if not isinstance(other, self.__class__):
            raise TypeError("Polynomial types differ")
        elif not np.all(self.domain == other.domain):
            raise TypeError("Domains differ")
        elif not np.all(self.window == other.window):
            raise TypeError("Windows differ")
        elif self.symbol != other.symbol:
            raise ValueError("Polynomial symbols differ")
        return other.coef
    return other

def __init__(self, coef, domain=None, window=None, symbol='x'):
    [coef] = pu.as_series([coef], trim=False)
    self.coef = coef

    if domain is not None:
        [domain] = pu.as_series([domain], trim=False)
        if len(domain) != 2:
            raise ValueError("Domain has wrong number of elements.")
        self.domain = domain

    if window is not None:
        [window] = pu.as_series([window], trim=False)
        if len(window) != 2:
            raise ValueError("Window has wrong number of elements.")
        self.window = window

    # Validation for symbol
    try:
        if not symbol.isidentifier():
            raise ValueError(
                "Symbol string must be a valid Python identifier"
            )
    # If a user passes in something other than a string, the above
    # results in an AttributeError. Catch this and raise a more
    # informative exception
    except AttributeError:
        raise TypeError("Symbol must be a non-empty string")

    self._symbol = symbol

def __repr__(self):
    coef = repr(self.coef)[6:-1]
    domain = repr(self.domain)[6:-1]
    window = repr(self.window)[6:-1]
    name = self.__class__.__name__
    return (f"{name}({coef}, domain={domain}, window={window}, "
            f"symbol='{self.symbol}')")

def __format__(self, fmt_str):
    if fmt_str == '':
        return self.__str__()
    if fmt_str not in ('ascii', 'unicode'):
        raise ValueError(
            f"Unsupported format string '{fmt_str}' passed to "
            f"{self.__class__}.__format__. Valid options are "
            f"'ascii' and 'unicode'"
        )
    if fmt_str == 'ascii':
        return self._generate_string(self._str_term_ascii)
    return self._generate_string(self._str_term_unicode)

def __str__(self):
    if self._use_unicode:
        return self._generate_string(self._str_term_unicode)
    return self._generate_string(self._str_term_ascii)

def _generate_string(self, term_method):
    """
    Generate the full string representation of the polynomial, using
    ``term_method`` to generate each polynomial term.
    """
    # Get configuration for line breaks
    linewidth = np.get_printoptions().get('linewidth', 75)
    if linewidth < 1:
        linewidth = 1
    out = pu.format_float(self.coef[0])

    off, scale = self.mapparms()

    scaled_symbol, needs_parens = self._format_term(pu.format_float,
                                                    off, scale)
    if needs_parens:
        scaled_symbol = '(' + scaled_symbol + ')'

    for i, coef in enumerate(self.coef[1:]):
        out += " "
        power = str(i + 1)
        # Polynomial coefficient
        # The coefficient array can be an object array with elements that
        # will raise a TypeError with >= 0 (e.g. strings or Python
        # complex). In this case, represent the coefficient as-is.
        try:
            if coef >= 0:
                next_term = "+ " + pu.format_float(coef, parens=True)
            else:
                next_term = "- " + pu.format_float(-coef, parens=True)
        except TypeError:
            next_term = f"+ {coef}"
        # Polynomial term
        next_term += term_method(power, scaled_symbol)
        # Length of the current line with next term added
        line_len = len(out.split('\n')[-1]) + len(next_term)
        # If not the last term in the polynomial, it will be two
        # characters longer due to the +/- with the next term
        if i < len(self.coef[1:]) - 1:
            line_len += 2
        # Handle linebreaking
        if line_len >= linewidth:
            next_term = next_term.replace(" ", "\n", 1)
        out += next_term
    return out

@classmethod
def _str_term_unicode(cls, i, arg_str):
    """
    String representation of single polynomial term using unicode
    characters for superscripts and subscripts.
    """
    if cls.basis_name is None:
        raise NotImplementedError(
            "Subclasses must define either a basis_name, or override "
            "_str_term_unicode(cls, i, arg_str)"
        )
    return (f"·{cls.basis_name}{i.translate(cls._subscript_mapping)}"
            f"({arg_str})")

@classmethod
def _str_term_ascii(cls, i, arg_str):
    """
    String representation of a single polynomial term using ** and _ to
    represent superscripts and subscripts, respectively.
    """
    if cls.basis_name is None:
        raise NotImplementedError(
            "Subclasses must define either a basis_name, or override "
            "_str_term_ascii(cls, i, arg_str)"
        )
    return f" {cls.basis_name}_{i}({arg_str})"

@classmethod
def _repr_latex_term(cls, i, arg_str, needs_parens):
    if cls.basis_name is None:
        raise NotImplementedError(
            "Subclasses must define either a basis name, or override "
            "_repr_latex_term(i, arg_str, needs_parens)")
    # since we always add parens, we don't care if the expression needs them
    return f"{{{cls.basis_name}}}_{{{i}}}({arg_str})"

@staticmethod
def _repr_latex_scalar(x, parens=False):
    # TODO: we're stuck with disabling math formatting until we handle
    # exponents in this function
    return fr'\text{{{pu.format_float(x, parens=parens)}}}'

def _format_term(self, scalar_format: Callable, off: float, scale: float):
    """ Format a single term in the expansion """
    if off == 0 and scale == 1:
        term = self.symbol
        needs_parens = False
    elif scale == 1:
        term = f"{scalar_format(off)} + {self.symbol}"
        needs_parens = True
    elif off == 0:
        term = f"{scalar_format(scale)}{self.symbol}"
        needs_parens = True
    else:
        term = (
            f"{scalar_format(off)} + "
            f"{scalar_format(scale)}{self.symbol}"
        )
        needs_parens = True
    return term, needs_parens

def _repr_latex_(self):
    # get the scaled argument string to the basis functions
    off, scale = self.mapparms()
    term, needs_parens = self._format_term(self._repr_latex_scalar,
                                           off, scale)

                                           off, scale)

    mute = r"\color{{LightGray}}{{{}}}".format

    parts = []
    for i, c in enumerate(self.coef):
        # prevent duplication of + and - signs
        if i == 0:
            coef_str = f"{self._repr_latex_scalar(c)}"
        elif not isinstance(c, numbers.Real):
            coef_str = f" + ({self._repr_latex_scalar(c)})"
        elif c >= 0:
            coef_str = f" + {self._repr_latex_scalar(c, parens=True)}"
        else:
            coef_str = f" - {self._repr_latex_scalar(-c, parens=True)}"

        # produce the string for the term
        term_str = self._repr_latex_term(i, term, needs_parens)
        if term_str == '1':
            part = coef_str
        else:
            part = rf"{coef_str}\,{term_str}"

        if c == 0:
            part = mute(part)

        parts.append(part)

    if parts:
        body = ''.join(parts)
    else:
        # in case somehow there are no coefficients at all
        body = '0'

    return rf"${self.symbol} \mapsto {body}$"

# Pickle and copy

def __getstate__(self):
    ret = self.__dict__.copy()
    ret['coef'] = self.coef.copy()
    ret['domain'] = self.domain.copy()
    ret['window'] = self.window.copy()
    ret['symbol'] = self.symbol
    return ret

def __setstate__(self, dict):
    self.__dict__ = dict

# Call

def __call__(self, arg):
    arg = pu.mapdomain(arg, self.domain, self.window)
    return self._val(arg, self.coef)

def __iter__(self):
    return iter(self.coef)

def __len__(self):
    return len(self.coef)

# Numeric properties.

def __neg__(self):
    return self.__class__(
        -self.coef, self.domain, self.window, self.symbol
    )

def __pos__(self):
    return self

def __add__(self, other):
    othercoef = self._get_coefficients(other)
    try:
        coef = self._add(self.coef, othercoef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __sub__(self, other):
    othercoef = self._get_coefficients(other)
    try:
        coef = self._sub(self.coef, othercoef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __mul__(self, other):
    othercoef = self._get_coefficients(other)
    try:
        coef = self._mul(self.coef, othercoef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __truediv__(self, other):
    # there is no true divide if the rhs is not a Number, although it
    # could return the first n elements of an infinite series.
    # It is hard to see where n would come from, though.
    if not isinstance(other, numbers.Number) or isinstance(other, bool):
        raise TypeError(
            f"unsupported types for true division: "
            f"'{type(self)}', '{type(other)}'"
        )
    return self.__floordiv__(other)

def __floordiv__(self, other):
    res = self.__divmod__(other)
    if res is NotImplemented:
        return res
    return res[0]

def __mod__(self, other):
    res = self.__divmod__(other)
    if res is NotImplemented:
        return res
    return res[1]

def __divmod__(self, other):
    othercoef = self._get_coefficients(other)
    try:
        quo, rem = self._div(self.coef, othercoef)
    except ZeroDivisionError:
        raise
    except Exception:
        return NotImplemented
    quo = self.__class__(quo, self.domain, self.window, self.symbol)
    rem = self.__class__(rem, self.domain, self.window, self.symbol)
    return quo, rem

def __pow__(self, other):
    coef = self._pow(self.coef, other, maxpower=self.maxpower)
    res = self.__class__(coef, self.domain, self.window, self.symbol)
    return res

def __radd__(self, other):
    try:
        coef = self._add(other, self.coef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __rsub__(self, other):
    try:
        coef = self._sub(other, self.coef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __rmul__(self, other):
    try:
        coef = self._mul(other, self.coef)
    except Exception:
        return NotImplemented
    return self.__class__(coef, self.domain, self.window, self.symbol)

def __rtruediv__(self, other):
    # An instance of ABCPolyBase is not considered a
    # Number.
    return NotImplemented

def __rfloordiv__(self, other):
    res = self.__rdivmod__(other)
    if res is NotImplemented:
        return res
    return res[0]

def __rmod__(self, other):
    res = self.__rdivmod__(other)
    if res is NotImplemented:
        return res
    return res[1]

def __rdivmod__(self, other):
    try:
        quo, rem = self._div(other, self.coef)
    except ZeroDivisionError:
        raise
    except Exception:
        return NotImplemented
    quo = self.__class__(quo, self.domain, self.window, self.symbol)
    rem = self.__class__(rem, self.domain, self.window, self.symbol)
    return quo, rem

def __eq__(self, other):
    res = (isinstance(other, self.__class__) and
           np.all(self.domain == other.domain) and
           np.all(self.window == other.window) and
           (self.coef.shape == other.coef.shape) and
           np.all(self.coef == other.coef) and
           (self.symbol == other.symbol))
    return res

def __ne__(self, other):
    return not self.__eq__(other)

#
# Extra methods.
#

def copy(self):
    """Return a copy.

    Returns
    -------
    new_series : series
        Copy of self.

    """
    return self.__class__(self.coef, self.domain, self.window, self.symbol)

def degree(self):
    """The degree of the series.

    Returns
    -------
    degree : int
        Degree of the series, one less than the number of coefficients.

    Examples
    --------

    Create a polynomial object for ``1 + 7*x + 4*x**2``:

    >>> np.polynomial.set_default_printstyle("unicode")
    >>> poly = np.polynomial.Polynomial([1, 7, 4])
    >>> print(poly)
    1.0 + 7.0·x + 4.0·x²
    >>> poly.degree()
    2

    Note that this method does not check for non-zero coefficients.
    You must trim the polynomial to remove any trailing zeroes:

    >>> poly = np.polynomial.Polynomial([1, 7, 0])
    >>> print(poly)
    1.0 + 7.0·x + 0.0·x²
    >>> poly.degree()
    2
    >>> poly.trim().degree()
    1

    """
    return len(self) - 1

def cutdeg(self, deg):
    """Truncate series to the given degree.

    Reduce the degree of the series to `deg` by discarding the
    high order terms. If `deg` is greater than the current degree a
    copy of the current series is returned. This can be useful in least
    squares where the coefficients of the high degree terms may be very
    small.

    Parameters
    ----------
    deg : non-negative int
        The series is reduced to degree `deg` by discarding the high
        order terms. The value of `deg` must be a non-negative integer.

    Returns
    -------
    new_series : series
        New instance of series with reduced degree.

    """
    return self.truncate(deg + 1)

def trim(self, tol=0):
    """Remove trailing coefficients

    Remove trailing coefficients until a coefficient is reached whose
    absolute value greater than `tol` or the beginning of the series is
    reached. If all the coefficients would be removed the series is set
    to ``[0]``. A new series instance is returned with the new
    coefficients.  The current instance remains unchanged.

    Parameters
    ----------
    tol : non-negative number.
        All trailing coefficients less than `tol` will be removed.

    Returns
    -------
    new_series : series
        New instance of series with trimmed coefficients.

    """
    coef = pu.trimcoef(self.coef, tol)
    return self.__class__(coef, self.domain, self.window, self.symbol)

def truncate(self, size):
    """Truncate series to length `size`.

    Reduce the series to length `size` by discarding the high
    degree terms. The value of `size` must be a positive integer. This
    can be useful in least squares where the coefficients of the
    high degree terms may be very small.

    Parameters
    ----------
    size : positive int
        The series is reduced to length `size` by discarding the high
        degree terms. The value of `size` must be a positive integer.

    Returns
    -------
    new_series : series
        New instance of series with truncated coefficients.

    """
    isize = int(size)
    if isize != size or isize < 1:
        raise ValueError("size must be a positive integer")
    if isize >= len(self.coef):
        coef = self.coef
    else:
        coef = self.coef[:isize]
    return self.__class__(coef, self.domain, self.window, self.symbol)

def convert(self, domain=None, kind=None, window=None):
    """Convert series to a different kind and/or domain and/or window.

    Parameters
    ----------
    domain : array_like, optional
        The domain of the converted series. If the value is None,
        the default domain of `kind` is used.
    kind : class, optional
        The polynomial series type class to which the current instance
        should be converted. If kind is None, then the class of the
        current instance is used.
    window : array_like, optional
        The window of the converted series. If the value is None,
        the default window of `kind` is used.

    Returns
    -------
    new_series : series
        The returned class can be of different type than the current
        instance and/or have a different domain and/or different
        window.

    Notes
    -----
    Conversion between domains and class types can result in
    numerically ill defined series.

    """
    if kind is None:
        kind = self.__class__
    if domain is None:
        domain = kind.domain
    if window is None:
        window = kind.window
    return self(kind.identity(domain, window=window, symbol=self.symbol))

def mapparms(self):
    """Return the mapping parameters.
